import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import './Practice.css';

function Practice() {
  const navigate = useNavigate();
  const [step, setStep] = useState('selection'); // selection, interview
  const [selectedRole, setSelectedRole] = useState(null);
  const [sessionId, setSessionId] = useState(null);
  const [messages, setMessages] = useState([]);
  const [currentAnswer, setCurrentAnswer] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [timeLimit, setTimeLimit] = useState(30); // minutes
  const [timeRemaining, setTimeRemaining] = useState(null);
  const [timerInterval, setTimerInterval] = useState(null);
  const [isTerminating, setIsTerminating] = useState(false);

  const roles = [
    {
      id: 'software-engineer',
      name: 'Software Engineer',
      icon: '💻',
      description: 'General software engineering questions covering algorithms, system design, and coding',
      questions: 15
    },
    {
      id: 'data-scientist',
      name: 'Data Scientist',
      icon: '📊',
      description: 'Data science and machine learning focused questions',
      questions: 12
    },
    {
      id: 'product-manager',
      name: 'Product Manager',
      icon: '📱',
      description: 'Product management and strategy questions',
      questions: 10
    },
    {
      id: 'frontend-developer',
      name: 'Frontend Developer',
      icon: '🎨',
      description: 'Frontend development and UI/UX questions',
      questions: 14
    },
    {
      id: 'backend-developer',
      name: 'Backend Developer',
      icon: '⚙️',
      description: 'Backend development and API design questions',
      questions: 13
    },
    {
      id: 'devops-engineer',
      name: 'DevOps Engineer',
      icon: '🔧',
      description: 'DevOps, CI/CD, and infrastructure questions',
      questions: 11
    }
  ];

  // Fullscreen and security features during interview
  useEffect(() => {
    if (step === 'interview') {
      // Request fullscreen
      const enterFullscreen = async () => {
        try {
          const elem = document.documentElement;
          if (elem.requestFullscreen) {
            await elem.requestFullscreen();
          } else if (elem.webkitRequestFullscreen) {
            await elem.webkitRequestFullscreen();
          } else if (elem.msRequestFullscreen) {
            await elem.msRequestFullscreen();
          }
        } catch (err) {
          console.log('Fullscreen request failed:', err);
        }
      };
      enterFullscreen();

      const handleBeforeUnload = (e) => {
        e.preventDefault();
        e.returnValue = 'Interview in progress. Are you sure you want to leave?';
        return e.returnValue;
      };

      const handlePopState = (e) => {
        if (window.confirm('Interview in progress. Are you sure you want to leave?')) {
          return true;
        } else {
          window.history.pushState(null, '', window.location.pathname);
          e.preventDefault();
          return false;
        }
      };

      // Prevent copy/paste and keyboard shortcuts
      const handleKeyDown = (e) => {
        // Prevent ESC key (exits fullscreen) - TERMINATE
        if (e.key === 'Escape') {
          e.preventDefault();
          if (!isTerminating) {
            handleFullscreenViolation();
          }
          return false;
        }

        // Prevent Ctrl+C, Ctrl+V, Ctrl+X, Ctrl+A
        if ((e.ctrlKey || e.metaKey) && ['c', 'v', 'x', 'a'].includes(e.key.toLowerCase())) {
          e.preventDefault();
          alert('⚠️ Copy/Paste is disabled during the interview!');
          return false;
        }
        // Prevent F12, Ctrl+Shift+I (DevTools)
        if (e.key === 'F12' || ((e.ctrlKey || e.metaKey) && e.shiftKey && e.key === 'I')) {
          e.preventDefault();
          return false;
        }
      };

      // Prevent right-click context menu
      const handleContextMenu = (e) => {
        e.preventDefault();
        alert('⚠️ Right-click is disabled during the interview!');
        return false;
      };

      // Prevent copy event
      const handleCopy = (e) => {
        e.preventDefault();
        alert('⚠️ Copying is disabled during the interview!');
        return false;
      };

      // Prevent paste event
      const handlePaste = (e) => {
        // Allow paste only in textarea
        if (e.target.tagName !== 'TEXTAREA') {
          e.preventDefault();
          alert('⚠️ Pasting is disabled during the interview!');
          return false;
        }
      };

      // Prevent cut event
      const handleCut = (e) => {
        e.preventDefault();
        alert('⚠️ Cutting is disabled during the interview!');
        return false;
      };

      // Detect fullscreen exit
      const handleFullscreenChange = () => {
        if (!document.fullscreenElement && !document.webkitFullscreenElement && !document.msFullscreenElement) {
          // User exited fullscreen (pressed ESC or clicked exit) - TERMINATE IMMEDIATELY
          if (!isTerminating) {
            handleFullscreenViolation();
          }
        }
      };

      // Handle fullscreen violation (ESC key or exit fullscreen)
      const handleFullscreenViolation = async () => {
        setIsTerminating(true);

        // Clear timer
        if (timerInterval) {
          clearInterval(timerInterval);
        }

        // Show alert
        alert('⛔ FULLSCREEN EXIT DETECTED!\n\nYour interview has been terminated due to exiting fullscreen mode.\n\nThis interview will NOT be saved and has been deleted from the system.');

        // Call backend to delete the interview
        try {
          const token = localStorage.getItem('token');
          await fetch(`http://localhost:5000/api/interview/${sessionId}/terminate`, {
            method: 'DELETE',
            headers: {
              'Authorization': `Bearer ${token}`,
              'Content-Type': 'application/json'
            }
          });
        } catch (error) {
          console.error('Failed to delete interview:', error);
        }

        // Redirect to dashboard
        setTimeout(() => {
          navigate('/dashboard');
        }, 1000);
      };

      window.addEventListener('beforeunload', handleBeforeUnload);
      window.history.pushState(null, '', window.location.pathname);
      window.addEventListener('popstate', handlePopState);
      document.addEventListener('keydown', handleKeyDown);
      document.addEventListener('contextmenu', handleContextMenu);
      document.addEventListener('copy', handleCopy);
      document.addEventListener('paste', handlePaste);
      document.addEventListener('cut', handleCut);
      document.addEventListener('fullscreenchange', handleFullscreenChange);
      document.addEventListener('webkitfullscreenchange', handleFullscreenChange);
      document.addEventListener('msfullscreenchange', handleFullscreenChange);

      return () => {
        window.removeEventListener('beforeunload', handleBeforeUnload);
        window.removeEventListener('popstate', handlePopState);
        document.removeEventListener('keydown', handleKeyDown);
        document.removeEventListener('contextmenu', handleContextMenu);
        document.removeEventListener('copy', handleCopy);
        document.removeEventListener('paste', handlePaste);
        document.removeEventListener('cut', handleCut);
        document.removeEventListener('fullscreenchange', handleFullscreenChange);
        document.removeEventListener('webkitfullscreenchange', handleFullscreenChange);
        document.removeEventListener('msfullscreenchange', handleFullscreenChange);

        // Exit fullscreen when interview ends
        if (document.fullscreenElement) {
          document.exitFullscreen();
        } else if (document.webkitFullscreenElement) {
          document.webkitExitFullscreen();
        } else if (document.msFullscreenElement) {
          document.msExitFullscreen();
        }
      };
    }
  }, [step]);

  // Detect tab visibility change - STRICT MODE
  useEffect(() => {
    if (step === 'interview' && !isTerminating) {
      const handleVisibilityChange = async () => {
        if (document.hidden) {
          // User switched tabs - terminate interview immediately
          setIsTerminating(true);

          // Clear timer
          if (timerInterval) {
            clearInterval(timerInterval);
          }

          // Show alert
          alert('⛔ TAB SWITCHING DETECTED!\n\nYour interview has been terminated due to switching tabs.\n\nThis interview will NOT be saved and has been deleted from the system.');

          // Call backend to delete the interview
          try {
            const token = localStorage.getItem('token');
            await fetch(`http://localhost:5000/api/interview/${sessionId}/terminate`, {
              method: 'DELETE',
              headers: {
                'Authorization': `Bearer ${token}`,
                'Content-Type': 'application/json'
              }
            });
          } catch (error) {
            console.error('Failed to delete interview:', error);
          }

          // Exit fullscreen
          if (document.fullscreenElement) {
            document.exitFullscreen();
          } else if (document.webkitFullscreenElement) {
            document.webkitExitFullscreen();
          } else if (document.msFullscreenElement) {
            document.msExitFullscreen();
          }

          // Redirect to dashboard
          setTimeout(() => {
            navigate('/dashboard');
          }, 1000);
        }
      };

      document.addEventListener('visibilitychange', handleVisibilityChange);

      return () => {
        document.removeEventListener('visibilitychange', handleVisibilityChange);
      };
    }
  }, [step, sessionId, timerInterval, navigate, isTerminating]);

  // Timer management
  useEffect(() => {
    if (step === 'interview' && timeRemaining !== null) {
      const interval = setInterval(() => {
        setTimeRemaining(prev => {
          if (prev <= 1) {
            clearInterval(interval);
            handleTimeUp();
            return 0;
          }

          // Warnings at specific times
          if (prev === 300) { // 5 minutes
            alert('⏰ 5 minutes remaining!');
          } else if (prev === 60) { // 1 minute
            alert('⏰ 1 minute remaining!');
          }

          return prev - 1;
        });
      }, 1000);

      setTimerInterval(interval);

      return () => {
        if (interval) clearInterval(interval);
      };
    }
  }, [step, timeRemaining]);

  const handleTimeUp = async () => {
    alert('⏰ Time is up! Your interview will be completed automatically.');
    await handleCompleteInterview();
  };

  const formatTime = (seconds) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const getTimeColor = () => {
    if (!timeRemaining) return '#48bb78';
    const percentage = (timeRemaining / (timeLimit * 60)) * 100;
    if (percentage > 50) return '#48bb78'; // green
    if (percentage > 25) return '#ed8936'; // orange
    return '#f56565'; // red
  };

  const handleStartPractice = async (role) => {
    // Show strict rules confirmation
    const confirmed = window.confirm(
      '⚠️ INTERVIEW RULES - PLEASE READ CAREFULLY:\n\n' +
      '1. Interview will run in FULLSCREEN mode\n' +
      '2. Copy/Paste is DISABLED\n' +
      '3. Right-click is DISABLED\n' +
      '4. Switching tabs (Alt+Tab/Ctrl+Tab) will IMMEDIATELY TERMINATE and DELETE your interview\n' +
      '5. Pressing ESC key will IMMEDIATELY TERMINATE and DELETE your interview\n' +
      '6. Your interview will NOT be saved if you violate these rules\n\n' +
      'Do you understand and agree to these rules?'
    );

    if (!confirmed) {
      return;
    }

    setSelectedRole(role);
    setLoading(true);
    setError('');

    try {
      const token = localStorage.getItem('token');

      if (!token) {
        setError('Please sign in to start practice interview');
        navigate('/signin');
        return;
      }

      const response = await fetch('http://localhost:5000/api/practice/start', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ roleId: role.id })
      });

      const data = await response.json();

      if (data.success) {
        setSessionId(data.session.id);
        setMessages([{
          type: 'ai',
          text: data.session.question
        }]);
        setTimeRemaining(timeLimit * 60); // Convert minutes to seconds
        setStep('interview');
      } else {
        setError(data.message || 'Failed to start practice interview');
      }
    } catch (error) {
      console.error('Start practice error:', error);
      setError('Network error. Please check your connection and try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleSendAnswer = async () => {
    if (!currentAnswer.trim() || loading) return;

    const userMessage = currentAnswer.trim();
    setCurrentAnswer('');
    setLoading(true);
    setError('');

    // Add user message to chat
    setMessages(prev => [...prev, {
      type: 'user',
      text: userMessage
    }]);

    try {
      const token = localStorage.getItem('token');
      const response = await fetch(`http://localhost:5000/api/interview/${sessionId}/answer`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ answer: userMessage })
      });

      const data = await response.json();

      if (data.success) {
        // Add AI response
        setMessages(prev => [...prev, {
          type: 'ai',
          text: data.question
        }]);
      } else {
        setError(data.message || 'Failed to get next question');
      }
    } catch (error) {
      console.error('Submit answer error:', error);
      setError('Network error. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const handleCompleteInterview = async () => {
    if (!sessionId || loading) return;

    const confirmed = window.confirm('Are you sure you want to complete this interview?');
    if (!confirmed) return;

    // Clear timer
    if (timerInterval) {
      clearInterval(timerInterval);
    }

    setLoading(true);
    setError('');

    try {
      const token = localStorage.getItem('token');
      const response = await fetch(`http://localhost:5000/api/interview/${sessionId}/complete`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        }
      });

      const data = await response.json();

      if (data.success) {
        // Redirect to dashboard to see results
        navigate('/dashboard');
      } else {
        setError(data.message || 'Failed to complete interview');
      }
    } catch (error) {
      console.error('Complete interview error:', error);
      setError('Failed to complete interview. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="practice-page">
      <div className="container">
        {error && <div className="alert alert-error">{error}</div>}

        {step === 'selection' && (
          <>
            <div className="practice-header fade-in">
              <h1>Practice Interviews</h1>
              <p>Choose a role to practice interview questions without uploading a resume</p>
            </div>

            <div className="roles-grid">
              {roles.map((role, index) => (
                <div 
                  key={role.id} 
                  className="role-card slide-in"
                  style={{animationDelay: `${index * 0.1}s`}}
                >
                  <div className="role-icon">{role.icon}</div>
                  <h3>{role.name}</h3>
                  <p>{role.description}</p>
                  <div className="role-meta">
                    <span className="question-count">📝 {role.questions} questions</span>
                  </div>
                  <button 
                    className="btn btn-primary btn-block"
                    onClick={() => handleStartPractice(role)}
                    disabled={loading}
                  >
                    {loading && selectedRole?.id === role.id ? 'Starting...' : 'Start Practice'}
                  </button>
                </div>
              ))}
            </div>

            <div className="practice-info">
              <div className="info-card">
                <h3>💡 How Practice Mode Works</h3>
                <ul>
                  <li>No resume required - jump right in</li>
                  <li>Role-specific questions tailored to the position</li>
                  <li>Get instant feedback on your answers</li>
                  <li>Track your progress across multiple sessions</li>
                  <li>Perfect for preparing for specific job roles</li>
                </ul>
              </div>

              <div className="info-card" style={{marginTop: '24px'}}>
                <h3>⏱️ Select Interview Duration</h3>
                <div className="time-options">
                  <button 
                    className={`time-option ${timeLimit === 30 ? 'active' : ''}`}
                    onClick={() => setTimeLimit(30)}
                  >
                    <div className="time-value">30</div>
                    <div className="time-label">Minutes</div>
                  </button>
                  <button 
                    className={`time-option ${timeLimit === 60 ? 'active' : ''}`}
                    onClick={() => setTimeLimit(60)}
                  >
                    <div className="time-value">60</div>
                    <div className="time-label">Minutes</div>
                  </button>
                  <button 
                    className={`time-option ${timeLimit === 120 ? 'active' : ''}`}
                    onClick={() => setTimeLimit(120)}
                  >
                    <div className="time-value">120</div>
                    <div className="time-label">Minutes</div>
                  </button>
                </div>
              </div>
            </div>
          </>
        )}

        {step === 'interview' && (
          <div className="interview-section fade-in">
            <div className="interview-warning">
              ⛔ STRICT MODE ACTIVE - Fullscreen required. Copy/Paste disabled. 
              <br />
              <strong>WARNING: Switching tabs (Alt+Tab/Ctrl+Tab) or pressing ESC will IMMEDIATELY TERMINATE and DELETE this interview!</strong>
            </div>
            <div className="interview-header">
              <div>
                <h1>Practice Interview: {selectedRole?.name}</h1>
                <p className="subtitle">Answer the questions to the best of your ability</p>
              </div>
              <div className="interview-controls">
                {timeRemaining !== null && (
                  <div className="timer" style={{ color: getTimeColor() }}>
                    <span className="timer-icon">⏱️</span>
                    <span className="timer-value">{formatTime(timeRemaining)}</span>
                  </div>
                )}
                <button 
                  onClick={handleCompleteInterview} 
                  className="btn btn-secondary"
                  disabled={loading || messages.length < 4}
                  title={messages.length < 4 ? 'Answer at least 2 questions before completing' : 'Complete interview'}
                >
                  Complete Interview
                </button>
              </div>
            </div>

            <div className="chat-container">
              {messages.map((msg, index) => (
                <div key={index} className={`message ${msg.type}-message`}>
                  <div className="message-avatar">
                    {msg.type === 'ai' ? '🤖' : '👤'}
                  </div>
                  <div className="message-content">
                    <p>{msg.text}</p>
                  </div>
                </div>
              ))}

              {loading && (
                <div className="message ai-message">
                  <div className="message-avatar">🤖</div>
                  <div className="message-content">
                    <p className="typing">Thinking...</p>
                  </div>
                </div>
              )}

              <div className="message-input-container">
                <textarea
                  className="message-input"
                  placeholder="Type your answer here..."
                  rows="4"
                  value={currentAnswer}
                  onChange={(e) => setCurrentAnswer(e.target.value)}
                  onKeyPress={(e) => {
                    if (e.key === 'Enter' && !e.shiftKey) {
                      e.preventDefault();
                      handleSendAnswer();
                    }
                  }}
                  disabled={loading}
                ></textarea>
                <button 
                  className="btn btn-primary" 
                  onClick={handleSendAnswer}
                  disabled={loading || !currentAnswer.trim()}
                >
                  {loading ? 'Sending...' : 'Send Answer'}
                </button>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

export default Practice;
